import React, { useState, useEffect } from "react";
import Dice from "react-dice-roll";

// --- Board Image path ---
const boardImage = "/torahpoly_board.png";

// ...existing property and boardEvents definitions...

// --- Build 44 board positions ---
function buildBoardPositions(refSize = 1200, margin = 100, spacesPerSide = 11) {
  const positions = [];
  const step = (refSize - 2 * margin) / (spacesPerSide - 1);

  const topY = margin;
  for (let i = 0; i < spacesPerSide; i++) positions.push({ x: Math.round(margin + i * step), y: topY });
  const rightX = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX, y: Math.round(topY + i * step) });
  const bottomY = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: Math.round(rightX - i * step), y: bottomY });
  const leftX = margin;
  for (let i = 1; i < spacesPerSide - 1; i++) positions.push({ x: leftX, y: Math.round(bottomY - i * step) });

  return positions.slice(0, 44);
}

const referenceSize = 1200;
const defaultBoardPositions = buildBoardPositions(referenceSize, 100, 11);

const calculateRent = (card) => {
  if (card.hotel) return card.rent.hotel;
  switch (card.houses) {
    case 3: return card.rent.house3;
    case 2: return card.rent.house2;
    case 1: return card.rent.house1;
    default: return card.rent.base;
  }
};

// --- Rescue Modal Component ---
function RescueModal({ rescue, players, onClose }) {
  if (!rescue.open || rescue.needyIndex === null) return null;
  const needy = players[rescue.needyIndex];
  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>Insufficient funds... Rescue {needy.name}</h2>
        <p>
          You owe ${rescue.amountDue + needy.money}, but only have ${needy.money}.<br />
          <strong>${rescue.amountDue} is still needed.</strong>
        </p>
        <h3>Option 1: Convert Money to Zchut</h3>
        <p>Get 2 Zchut for every $1. You currently have {needy.zchutPoints} Zchut.</p>
        {/* Option 2 and 3 will be added next */}
        <button style={modalStyles.button} onClick={onClose}>Close</button>
      </div>
    </div>
  );
}

// --- Modal Component ---
function CardModal({ card, onClose, mode, currentPlayer, updatePlayer, players, updatePlayers, onRescueOpen }) {
  if (!card) return null;
  const isProperty = mode === "property";

  const handleBuyProperty = () => {
    if (currentPlayer.money < card.price) { alert("Not enough money!"); return; }
    const updatedPlayers = [...players];
    updatedPlayers[currentPlayer.index] = { ...currentPlayer, money: currentPlayer.money - card.price };
    card.ownerIndex = currentPlayer.index;
    updatePlayers(updatedPlayers);
    alert(`${currentPlayer.name} bought ${card.name} for $${card.price}`);
    onClose();
  };

  const handlePayRent = () => {
    if (card.ownerIndex === null || card.ownerIndex === currentPlayer.index) {
      alert("No rent needed.");
      onClose();
      return;
    }

    const rentAmount = calculateRent(card);

    if (currentPlayer.money >= rentAmount) {
      const updatedPlayers = [...players];
      updatedPlayers[currentPlayer.index].money -= rentAmount;
      updatedPlayers[card.ownerIndex].money += rentAmount;
      updatePlayers(updatedPlayers);
      alert(`${currentPlayer.name} paid $${rentAmount} rent to ${players[card.ownerIndex].name}`);
      onClose();
    } else {
      // Open rescue modal
      const shortfall = rentAmount - currentPlayer.money;
      if (onRescueOpen) onRescueOpen(currentPlayer.index, shortfall, { type: "rent", payerId: currentPlayer.index, ownerId: card.ownerIndex, amount: rentAmount });
      onClose();
    }
  };

  // ...existing handleTrade and modal rendering code...

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>{card.name}</h2>
        {isProperty && (
          <>
            {/* ...existing property details... */}
            {card.ownerIndex === null && <button style={{ ...modalStyles.button, backgroundColor: "green" }} onClick={handleBuyProperty}>Buy Property</button>}
            {card.ownerIndex !== currentPlayer.index && card.ownerIndex !== null && <button style={{ ...modalStyles.button, backgroundColor: "orange" }} onClick={handlePayRent}>Pay Rent</button>}
            {/* ...existing trade button... */}
            <button style={modalStyles.button} onClick={onClose}>Close</button>
          </>
        )}
      </div>
    </div>
  );
}

// --- Player Panel Modal (unchanged) ---
function PlayerPanelModal({ player, onClose }) {
  // ...existing code...
}

// --- Main App ---
function App() {
  const [players, setPlayers] = useState([]);
  const [newPlayerName, setNewPlayerName] = useState("");
  const [newPlayerColor, setNewPlayerColor] = useState("");
  const [gameStarted, setGameStarted] = useState(false);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [qaMode, setQaMode] = useState(false);
  const [currentCard, setCurrentCard] = useState(null);
  const [boardWidth, setBoardWidth] = useState(Math.min(window.innerWidth * 0.95, referenceSize));
  const [boardPositions, setBoardPositions] = useState(defaultBoardPositions);
  const [diceRolls, setDiceRolls] = useState([]);
  const [showPanel, setShowPanel] = useState(null);

  // Rescue modal state
  const [rescue, setRescue] = useState({ open: false, needyIndex: null, amountDue: 0, rentInfo: null });

  // Handler to open rescue modal
  const handleRescueOpen = (needyIndex, amountDue, rentInfo) => {
    setRescue({ open: true, needyIndex, amountDue, rentInfo });
  };
  const handleRescueClose = () => {
    setRescue({ open: false, needyIndex: null, amountDue: 0, rentInfo: null });
  };

  // ...existing addPlayer, startGame, updateCurrentPlayer, movePlayerBy, rollDice, endTurn, handleSquareClick...

  return (
    <div style={styles.container}>
      <h1>TorahPoly Monopoly Game</h1>

      {/* ...existing player join and game board UI... */}

      {/* Property Modal */}
      {qaMode && currentCard && (
        <CardModal
          card={currentCard}
          mode={qaMode}
          currentPlayer={players[currentPlayerIndex]}
          updatePlayer={updateCurrentPlayer}
          players={players}
          updatePlayers={setPlayers}
          onClose={() => setQaMode(false)}
          onRescueOpen={handleRescueOpen}
        />
      )}

      {/* Rescue Modal */}
      <RescueModal rescue={rescue} players={players} onClose={handleRescueClose} />

      {/* Player Panel Modal */}
      {showPanel !== null && (
        <PlayerPanelModal player={players[showPanel]} onClose={() => setShowPanel(null)} />
      )}
    </div>
  );
}

// --- Styles ---
const styles = { container: { fontFamily: "Arial, sans-serif", padding: 20, backgroundColor: "#f0f2f5", minHeight: "100vh", textAlign: "center" }, button: { backgroundColor: "#007bff", color: "white", border: "none", borderRadius: 8, padding: "10px 20px", fontSize: 16, cursor: "pointer", margin: "5px" }, input: { fontSize: 16, padding: "5px 10px", borderRadius: 4, border: "1px solid #ccc" }, inputRow: { display: "flex", justifyContent: "center", gap: 10, marginBottom: 20 } };

const modalStyles = { overlay: { position: "fixed", top: 0, left: 0, right: 0, bottom: 0, backgroundColor: "rgba(0,0,0,0.5)", display: "flex", justifyContent: "center", alignItems: "center", zIndex: 1000 }, modal: { backgroundColor: "#fff", padding: 30, borderRadius: 12, minWidth: 300, maxWidth: "90%", textAlign: "center", boxShadow: "0 5px 15px rgba(0,0,0,0.3)" }, button: { margin: "8px 5px", padding: "8px 15px", borderRadius: 6, border: "none", backgroundColor: "#007bff", color: "#fff", fontSize: 14, cursor: "pointer" }};

export default App;
